exercises.solution_code:
#include <iostream>

int main()
{
    const char* days[]{ "Sunday", "Monday", "Tuesday",
        "Wednesday", "Thursday", "Friday", "Saturday" };

    int n{};
    std::cin >> n;

    if (n >= 0 && n <= 6)
        std::cout << days[n] << '\n';
    else
        std::cout << "invalid" << '\n';

    return 0;
}

